#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    string s, t;    cin >> s >> t;    int freq_s[26] = {0};    int freq_t[26] = {0};    for (int i = 0; i < s.length(); i++) {        char c = s[i];        freq_s[c - 'A']++;    }    for (int i = 0; i < t.length(); i++) {        char c = t[i];        freq_t[c - 'A']++;    }    for (int i = 0; i < 26; i++) {        if (freq_s[i] - freq_t[i] >0) {            int diff = freq_s[i] - freq_t[i];            for (int j = 0; j < s.length(); j++) {                if (s[j] - 'A' == i && diff > 0) {                    s.erase(s.begin() + j);                    diff--;                    j--; // Adjust index after erasing                }            }                    }            }    if (s == t) {        cout << "YES\n";    } else {        cout << "NO\n";    }     } // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}